import {
  Document, Packer, Paragraph, TextRun, Table, TableRow, TableCell,
  HeadingLevel, AlignmentType, BorderStyle, WidthType, ShadingType,
  LevelFormat, PageNumber, Footer, Header, TabStopType, TabStopPosition,
  UnderlineType
} from 'docx';
import fs from 'fs';

// ── Color palette ──
const C = {
  accent:   "1A56DB",   // blue
  accent2:  "0E9F6E",   // green
  accent3:  "E3A008",   // amber
  accent4:  "E02424",   // red
  dark:     "1F2A37",
  mid:      "4B5563",
  light:    "9CA3AF",
  bg1:      "EFF6FF",   // blue tint
  bg2:      "ECFDF5",   // green tint
  bg3:      "FFFBEB",   // amber tint
  bg4:      "FEF2F2",   // red tint
  bgGray:   "F9FAFB",
  border:   "E5E7EB",
  white:    "FFFFFF",
};

const FONT = "Malgun Gothic";
const border = { style: BorderStyle.SINGLE, size: 1, color: C.border };
const borders = { top: border, bottom: border, left: border, right: border };
const noBorder = { style: BorderStyle.NONE, size: 0, color: "FFFFFF" };
const noBorders = { top: noBorder, bottom: noBorder, left: noBorder, right: noBorder };

function sp(n = 0) {
  return new Paragraph({ children: [], spacing: { before: n, after: 0 } });
}

function h1(text) {
  return new Paragraph({
    heading: HeadingLevel.HEADING_1,
    spacing: { before: 360, after: 120 },
    border: { bottom: { style: BorderStyle.SINGLE, size: 8, color: C.accent, space: 4 } },
    children: [new TextRun({ text, font: FONT, size: 34, bold: true, color: C.accent })]
  });
}

function h2(text) {
  return new Paragraph({
    heading: HeadingLevel.HEADING_2,
    spacing: { before: 280, after: 80 },
    children: [new TextRun({ text, font: FONT, size: 26, bold: true, color: C.dark })]
  });
}

function h3(text) {
  return new Paragraph({
    heading: HeadingLevel.HEADING_3,
    spacing: { before: 200, after: 60 },
    children: [new TextRun({ text, font: FONT, size: 22, bold: true, color: C.mid })]
  });
}

function body(text, opts = {}) {
  return new Paragraph({
    spacing: { before: 60, after: 60 },
    children: [new TextRun({ text, font: FONT, size: 20, color: C.dark, ...opts })]
  });
}

function bullet(text, level = 0) {
  return new Paragraph({
    numbering: { reference: "bullets", level },
    spacing: { before: 40, after: 40 },
    children: [new TextRun({ text, font: FONT, size: 20, color: C.dark })]
  });
}

function checkItem(text) {
  return new Paragraph({
    numbering: { reference: "checks", level: 0 },
    spacing: { before: 40, after: 40 },
    children: [new TextRun({ text, font: FONT, size: 20, color: C.dark })]
  });
}

function codeBlock(lines) {
  const children = lines.flatMap((line, i) => {
    const runs = [new TextRun({ text: line, font: "Courier New", size: 18, color: "D1D5DB" })];
    if (i < lines.length - 1) runs.push(new TextRun({ break: 1 }));
    return runs;
  });
  return new Paragraph({
    spacing: { before: 80, after: 80 },
    shading: { fill: "1F2937", type: ShadingType.CLEAR },
    indent: { left: 240, right: 240 },
    children,
  });
}

function infoBox(text, bg, borderColor) {
  return new Table({
    width: { size: 9360, type: WidthType.DXA },
    columnWidths: [9360],
    rows: [
      new TableRow({
        children: [
          new TableCell({
            borders: {
              top: { style: BorderStyle.SINGLE, size: 6, color: borderColor },
              bottom: { style: BorderStyle.SINGLE, size: 1, color: borderColor },
              left: { style: BorderStyle.SINGLE, size: 12, color: borderColor },
              right: { style: BorderStyle.SINGLE, size: 1, color: borderColor },
            },
            shading: { fill: bg, type: ShadingType.CLEAR },
            margins: { top: 120, bottom: 120, left: 200, right: 200 },
            width: { size: 9360, type: WidthType.DXA },
            children: [
              new Paragraph({
                spacing: { before: 0, after: 0 },
                children: [new TextRun({ text, font: FONT, size: 19, color: C.dark })]
              })
            ]
          })
        ]
      })
    ]
  });
}

function twoColTable(rows, col1W = 3000, col2W = 6360) {
  return new Table({
    width: { size: 9360, type: WidthType.DXA },
    columnWidths: [col1W, col2W],
    rows: rows.map(([label, value], i) =>
      new TableRow({
        children: [
          new TableCell({
            borders,
            shading: { fill: i === 0 ? C.accent : C.bgGray, type: ShadingType.CLEAR },
            margins: { top: 80, bottom: 80, left: 120, right: 120 },
            width: { size: col1W, type: WidthType.DXA },
            children: [new Paragraph({ children: [new TextRun({ text: label, font: FONT, size: 19, bold: i === 0, color: i === 0 ? C.white : C.mid })] })]
          }),
          new TableCell({
            borders,
            shading: { fill: i === 0 ? C.bg1 : C.white, type: ShadingType.CLEAR },
            margins: { top: 80, bottom: 80, left: 120, right: 120 },
            width: { size: col2W, type: WidthType.DXA },
            children: [new Paragraph({ children: [new TextRun({ text: value, font: FONT, size: 19, bold: i === 0, color: i === 0 ? C.accent : C.dark })] })]
          }),
        ]
      })
    )
  });
}

// ── Document ──
